/**
 * BidChat — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "BidChat" (panel 316×677)
 *
 * Un solo panel 316×677 (gradiente morado + glass white 8% + borde gradiente,
 * radio 16, backdrop-blur 14, sombra) que contiene TODO:
 *   · Los BidMessage son el bg y van hasta arriba (su bg/borde es el del panel).
 *   · BidProposal (bid actual, 280×78) montado ENCIMA, arriba al centro.
 *   · ProgressBar 424×22 (rainbow, recortada al panel) sin esquinas redondeadas.
 *   · Botón primary 200×48 (solo el monto) abajo; al presionarlo dispara el
 *     efecto de luz del bid actual.
 */

"use client";

import { useState } from "react";
import type { JSX } from "react";
import BidProposal from "../../components/BidProposal/BidProposal";
import BidMessage from "../../components/BidMessage/BidMessage";
import ProgressBar from "../../components/ProgressBar/ProgressBar";
import Button from "../../components/Button/Button";

export interface BidChatProps {
  className?: string;
  /** Colores del efecto de luz del bid actual (editable). Default: primary. */
  flashColors?: string[];
  /** Tipo de efecto de luz: "bulb" (bombilla) o "spin" (gira). Default "bulb". */
  flashMode?: "bulb" | "spin" | "explode" | "pulse" | "combo" | "shine";
}

export const BIDCHAT_WIDTH = 316;
export const BIDCHAT_HEIGHT = 677;

const USER = "KAHTH4";
const AMOUNT = "US$ 5,079";
const STEP = 79;

function fmtMoney(n: number): string {
  return "US$ " + String(n).replace(/\B(?=(\d{3})+(?!\d))/g, ",");
}

const VMC_LOGO = <img src="/logo-preview.png" alt="VMC SUBASTAS" style={{ height: 16, width: "auto", display: "block" }} />;

// 4 bloques: propuesta (blanca/izq · naranja/live a la der) → "Cierra en" → VMC.
// El 2º y 4º son "live" (naranja, der); los demás blancos a la izquierda.
const PROPOSAL_TYPES = ["white", "live", "white", "live"] as const;
function buildMessages(): JSX.Element[] {
  const out: JSX.Element[] = [];
  PROPOSAL_TYPES.forEach(function block(propType, i) {
    const side = propType === "live" ? "sent" : "received";
    out.push(
      <BidMessage key={`p${i}`} side={side} type={propType}>
        <strong>{USER}</strong> ha propuesto <strong>{AMOUNT}</strong>
      </BidMessage>,
    );
    out.push(
      <BidMessage key={`c${i}`} side="received" type="vault">
        Cierra en <strong>{AMOUNT}</strong>
      </BidMessage>,
    );
    out.push(
      <BidMessage key={`v${i}`} side="received" type="vault" logo={VMC_LOGO}>
        A la una
      </BidMessage>,
    );
  });
  return out;
}

// Panel: morado (paint0) + glass white 8% + borde gradiente (paint1)
const PANEL_BG = "linear-gradient(0deg, rgba(255,255,255,0.08), rgba(255,255,255,0.08)), linear-gradient(115deg, #5F3ED8 0%, #340091 50%, #140046 100%)";
const PANEL_BORDER = "linear-gradient(120deg, #ffffff 0%, #F4AC59 22%, #8460E5 74.5%, #ffffff 100%)";

const STYLE_ID = "concorde-bidchat-styles";
const BIDCHAT_STYLES = `
/* Lista de mensajes (ocupa el panel hasta arriba) · scroll oculto */
.bidchat-list { scrollbar-width: none; -ms-overflow-style: none; }
.bidchat-list::-webkit-scrollbar { width: 0; height: 0; display: none; }
.bidchat-list .pbidmsg { font-size: 13px; }
.bidchat-list .pbidmsg--sent { align-self: flex-end; }
/* ProgressBar 424×22 sin esquinas redondeadas (recortada al panel) */
.bidchat-prog .pprogbar { border-radius: 0; width: 424px; height: 22px; }
/* CTA 200×48, solo el monto */
.bidchat-cta .pvbtn { width: 200px; padding: 0; }
`;

let _stylesInjected = false;

export default function BidChat({ className = "", flashColors, flashMode = "bulb" }: BidChatProps): JSX.Element {
  const [flash, setFlash] = useState(0);
  const [bidActual, setBidActual] = useState(6559);
  const [nextBid, setNextBid] = useState(7000);

  if (typeof document !== "undefined" && !_stylesInjected) {
    if (!document.getElementById(STYLE_ID)) {
      const el = document.createElement("style");
      el.id = STYLE_ID;
      el.textContent = BIDCHAT_STYLES;
      document.head.appendChild(el);
    }
    _stylesInjected = true;
  }

  // Click en el botón → pujo yo: sube el bid actual y se enciende el efecto de luz
  function handleBid(): void {
    setBidActual(nextBid);
    setNextBid((n) => n + STEP);
    setFlash((f) => f + 1);
  }

  return (
    <div
      className={className}
      data-block-section="bidchat"
      style={{
        boxSizing: "border-box",
        position: "relative",
        width: BIDCHAT_WIDTH,
        height: BIDCHAT_HEIGHT,
        borderRadius: 16,
        backgroundImage: `${PANEL_BG}, ${PANEL_BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, padding-box, border-box",
        border: "1.5px solid transparent",
        backdropFilter: "blur(14px)",
        WebkitBackdropFilter: "blur(14px)",
        boxShadow: "rgba(20,0,69,0.3) 0px 8px 24px -2px",
        overflow: "hidden",
      }}
    >
      <style id={`${STYLE_ID}-ssr`} suppressHydrationWarning dangerouslySetInnerHTML={{ __html: BIDCHAT_STYLES }} />

      {/* Lista de BidMessage — son el bg y van hasta arriba (scroll), por debajo del bid actual */}
      <div
        className="bidchat-list"
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 108,
          overflowY: "auto",
          padding: "16px 16px",
          display: "flex",
          flexDirection: "column",
          alignItems: "flex-start",
          gap: 8,
        }}
      >
        {buildMessages()}
      </div>

      {/* Bid actual (glass) 280×78 — arriba al centro, ENCIMA de los mensajes */}
      <div style={{ position: "absolute", top: 14, left: 0, right: 0, display: "flex", justifyContent: "center", zIndex: 3 }}>
        <BidProposal amount={fmtMoney(bidActual)} label="ENVIADO POR KAHTH4" flash={flash} flashColors={flashColors} flashMode={flashMode} />
      </div>

      {/* ProgressBar rainbow 424×22 (sin rounded) — recortada al panel */}
      <div className="bidchat-prog" style={{ position: "absolute", left: 0, bottom: 80, height: 22, zIndex: 5 }}>
        <ProgressBar variant="rainbow" value={40} aria-label="Tiempo de bid" />
      </div>

      {/* Botón 200×48 (solo el monto) abajo — al presionarlo dispara el efecto de luz */}
      <div className="bidchat-cta" style={{ position: "absolute", left: 0, right: 0, bottom: 16, display: "flex", justifyContent: "center", zIndex: 5 }}>
        <Button variant="primary" onClick={handleBid}>{fmtMoney(nextBid)}</Button>
      </div>
    </div>
  );
}

/**
 * ChatArea — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "Frame 1000022968" (área de mensajes 278×478)
 *
 * Fondo del área de mensajes del chat: morado translúcido (#5A35C2 40%),
 * radio 16 y borde superior sutil (white 0.1 → transparent). Por ahora es
 * solo el fondo; en el bottom va la ProgressBar (tiempo de bid) tal cual el
 * SVG. La lista de mensajes se montará encima vía `children`.
 */

import type { JSX, ReactNode } from "react";
import ProgressBar from "../../components/ProgressBar/ProgressBar";

// Scrollbar oculto · burbujas con texto más pequeño · los "sent" alineados a la derecha
const CHATAREA_LIST_CSS = `
.chatarea__list { scrollbar-width: none; -ms-overflow-style: none; }
.chatarea__list::-webkit-scrollbar { width: 0; height: 0; display: none; }
.chatarea__list .pbidmsg { font-size: 12px; }
.chatarea__list .pbidmsg--sent { align-self: flex-end; }
`;

export interface ChatAreaProps {
  /** Progreso de la barra inferior 0-100 (default 34, tal cual el SVG) */
  progress?: number;
  className?: string;
  /** Lista de mensajes (se monta encima del fondo) */
  children?: ReactNode;
}

export const CHATAREA_WIDTH = 278;
export const CHATAREA_HEIGHT = 478;

// Relleno morado translúcido (#5A35C2 @ 40%)
const FILL = "linear-gradient(rgba(90,53,194,0.4), rgba(90,53,194,0.4))";
// Borde: highlight blanco sutil arriba (paint13: white 0.1 → transparent)
const BORDER = "linear-gradient(180deg, rgba(255,255,255,0.1) 0%, rgba(255,255,255,0) 55%)";

export default function ChatArea({
  progress = 34,
  className = "",
  children,
}: ChatAreaProps): JSX.Element {
  return (
    <div
      className={className}
      data-block-section="chat-area"
      style={{
        boxSizing: "border-box",
        position: "relative",
        width: CHATAREA_WIDTH,
        height: CHATAREA_HEIGHT,
        borderRadius: 16,
        backgroundImage: `${FILL}, ${BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, border-box",
        border: "1.5px solid transparent",
        overflow: "hidden",
      }}
    >
      {/* Lista de mensajes · scrollable (sin scrollbar), por encima de la ProgressBar */}
      <style suppressHydrationWarning dangerouslySetInnerHTML={{ __html: CHATAREA_LIST_CSS }} />
      <div
        className="chatarea__list"
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          right: 0,
          bottom: 22,
          overflowY: "auto",
          padding: 16,
          display: "flex",
          flexDirection: "column",
          alignItems: "flex-start",
          gap: 8,
        }}
      >
        {children}
      </div>

      {/* ProgressBar (tiempo de bid) pegada al fondo, full-width */}
      <div style={{ position: "absolute", left: 0, right: 0, bottom: 0 }}>
        <ProgressBar value={progress} />
      </div>
    </div>
  );
}

"use client";

/**
 * ConsoleHeader — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "ConsoleHeader" (2934:14478)
 *
 * Barra 991×64 (gradiente morado #5F3ED8→#140046, borde gradiente, sombra).
 * Izquierda: AvatarZone + "Mi C.U.U. ZAEX5G". Derecha: 4 columnas con divisores:
 *   · CONECTADOS  → PriceBadge + número
 *   · OFERTA      → BadgeStatus (live, editable, sin dot)
 *   · FONDOS      → texto
 *   · CONECTIVIDAD→ Signal
 * Compuesta con componentes Concorde.
 */

import type { JSX, ReactNode } from "react";
import AvatarZone from "../../components/AvatarZone/AvatarZone";
import PriceBadge from "../../components/PriceBadge/PriceBadge";
import BadgeStatus from "../../components/BadgeStatus/BadgeStatus";
import Signal from "../../components/Signal/Signal";

export const CONSOLEHEADER_WIDTH = 991;
export const CONSOLEHEADER_HEIGHT = 64;

// Dark glass (paint0 + "behind transparent areas" #0A002E): base navy + sheen
// blanco (white 28%→4%) + borde gradiente (white .9 → #F4AC59 .7 → #8460E5 .7 → white .9)
const GLASS_SHEEN = "linear-gradient(127deg, rgba(255,255,255,0.22) 0%, rgba(255,255,255,0.07) 45%, rgba(255,255,255,0.03) 100%)";
const GLASS_BASE = "linear-gradient(160deg, rgba(28,13,82,0.93) 0%, rgba(14,3,56,0.95) 100%)";
const GLASS_BORDER = "linear-gradient(125deg, rgba(255,255,255,0.9) 0%, rgba(244,172,89,0.7) 22%, rgba(132,96,229,0.7) 74.5%, rgba(255,255,255,0.9) 100%)";

export interface ConsoleHeaderProps {
  userLabel?: string;
  user?: string;
  conectados?: string;
  oferta?: string;
  fondos?: string;
  conectividad?: number;
  className?: string;
}

function StatCol({ label, children }: { label: string; children: ReactNode }): JSX.Element {
  return (
    <div style={{ display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 6, padding: "0 18px", minWidth: 0 }}>
      <span style={{ fontSize: 9, fontWeight: 700, letterSpacing: "0.06em", textTransform: "uppercase", color: "#ffffff", whiteSpace: "nowrap" }}>{label}</span>
      <div style={{ display: "flex", alignItems: "center", justifyContent: "center", height: 22 }}>{children}</div>
    </div>
  );
}

function Divider(): JSX.Element {
  return <div style={{ width: 1, height: 44, background: "rgba(225,227,226,0.32)", flexShrink: 0 }} />;
}

export default function ConsoleHeader({
  userLabel = "Mi C.U.U.",
  user = "ZAEX5G",
  conectados = "18",
  oferta = "47292",
  fondos = "$100",
  conectividad = 4,
  className = "",
}: ConsoleHeaderProps): JSX.Element {
  return (
    <header
      className={className}
      style={{
        boxSizing: "border-box",
        width: CONSOLEHEADER_WIDTH,
        height: CONSOLEHEADER_HEIGHT,
        display: "flex",
        alignItems: "center",
        justifyContent: "space-between",
        padding: "0 16px",
        borderRadius: 16,
        border: "1.5px solid transparent",
        backgroundImage: `${GLASS_SHEEN}, ${GLASS_BASE}, ${GLASS_BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, padding-box, border-box",
        backdropFilter: "blur(20px)",
        WebkitBackdropFilter: "blur(20px)",
        boxShadow: "rgba(10,0,46,0.6) 0px 12px 36px -4px, inset 0 1px 0 rgba(255,255,255,0.22)",
        fontFamily: "var(--vmc-font-display, 'Plus Jakarta Sans', -apple-system, sans-serif)",
      }}
    >
      {/* Izquierda: avatar + usuario */}
      <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
        <AvatarZone size={32} />
        <div style={{ display: "flex", alignItems: "baseline", gap: 6, color: "#ffffff", whiteSpace: "nowrap" }}>
          <span style={{ fontSize: 15, fontWeight: 500 }}>{userLabel}</span>
          <span style={{ fontSize: 16, fontWeight: 800, letterSpacing: "0.01em" }}>{user}</span>
        </div>
      </div>

      {/* Derecha: 4 columnas con divisores */}
      <div style={{ display: "flex", alignItems: "center" }}>
        <StatCol label="Conectados">
          <span style={{ display: "flex", alignItems: "center", gap: 6 }}>
            <PriceBadge size={20} />
            <span style={{ fontSize: 16, fontWeight: 700, color: "#ffffff", fontVariantNumeric: "tabular-nums" }}>{conectados}</span>
          </span>
        </StatCol>
        <Divider />
        <StatCol label="Oferta">
          <BadgeStatus variant="live" label={oferta} icon={false} />
        </StatCol>
        <Divider />
        <StatCol label="Fondos">
          <span style={{ fontSize: 18, fontWeight: 800, color: "#ffffff", fontVariantNumeric: "tabular-nums", letterSpacing: "0.04em" }}>{fondos}</span>
        </StatCol>
        <Divider />
        <StatCol label="Conectividad">
          <Signal level={conectividad} width={30} />
        </StatCol>
      </div>
    </header>
  );
}

/**
 * PriceBase — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "Background+Shadow" (card 272×106)
 *
 * Card "PRECIO BASE / US$ 5,000": fondo morado degradado, borde superior sutil
 * y sombra. Reusa el componente PriceIcon (la gema). Editable por props.
 */

import type { JSX } from "react";
import PriceIcon from "../../components/PriceIcon/PriceIcon";

export interface PriceBaseProps {
  /** Etiqueta superior (default "PRECIO BASE") */
  label?: string;
  /** Monto (default "US$ 5,000") */
  amount?: string;
  className?: string;
}

export const PRICEBASE_WIDTH = 272;
export const PRICEBASE_HEIGHT = 106;

// Dark glass (paint0 + "behind transparent areas" #0A002E): base navy + sheen
// blanco (white 28%→4%) + borde gradiente (white .9 → #F4AC59 .7 → #8460E5 .7 → white .9)
const GLASS_SHEEN = "linear-gradient(127deg, rgba(255,255,255,0.22) 0%, rgba(255,255,255,0.07) 45%, rgba(255,255,255,0.03) 100%)";
const GLASS_BASE = "linear-gradient(160deg, rgba(28,13,82,0.93) 0%, rgba(14,3,56,0.95) 100%)";
const GLASS_BORDER = "linear-gradient(125deg, rgba(255,255,255,0.9) 0%, rgba(244,172,89,0.7) 22%, rgba(132,96,229,0.7) 74.5%, rgba(255,255,255,0.9) 100%)";

export default function PriceBase({
  label = "PRECIO BASE",
  amount = "US$ 5,000",
  className = "",
}: PriceBaseProps): JSX.Element {
  return (
    <div
      className={className}
      data-slot="price-base"
      style={{
        boxSizing: "border-box",
        width: PRICEBASE_WIDTH,
        height: PRICEBASE_HEIGHT,
        borderRadius: 16,
        backgroundImage: `${GLASS_SHEEN}, ${GLASS_BASE}, ${GLASS_BORDER}`,
        backgroundOrigin: "border-box",
        backgroundClip: "padding-box, padding-box, border-box",
        border: "1.5px solid transparent",
        backdropFilter: "blur(20px)",
        WebkitBackdropFilter: "blur(20px)",
        boxShadow: "rgba(10,0,46,0.6) 0px 12px 36px -4px, inset 0 1px 0 rgba(255,255,255,0.22)",
        padding: "16px 20px",
        display: "flex",
        flexDirection: "column",
        justifyContent: "space-between",
        fontFamily: 'var(--vmc-font-display, "Plus Jakarta Sans", -apple-system, sans-serif)',
      }}
    >
      <span
        style={{
          fontSize: 13,
          fontWeight: 700,
          letterSpacing: "0.06em",
          color: "#ffffff",
          textTransform: "uppercase",
        }}
      >
        {label}
      </span>
      <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
        <PriceIcon size="md" title="Precio base" />
        <span
          style={{
            fontSize: 30,
            fontWeight: 800,
            lineHeight: 1,
            color: "#ffffff",
            fontVariantNumeric: "tabular-nums",
          }}
        >
          {amount}
        </span>
      </div>
    </div>
  );
}

/**
 * Sala — Bloque de Concorde (Voyager DS)
 *
 * Sala de subasta. Por ahora es solo el lienzo base: un fondo de 1023 × 1042
 * con el color de marca (#2E0F70). Iremos montando las secciones encima.
 */

import type { JSX } from "react";
import ConsoleHeader from "./ConsoleHeader";
import PriceBase from "./PriceBase";
import StatPill from "./StatPill";
import BidChat from "./BidChat";
import SalaStatus from "../../components/SalaStatus/SalaStatus";
import CardViewer from "../../components/CardViewer/CardViewer";
import BidPosition from "../../components/BidPosition/BidPosition";

export interface SalaProps {
  className?: string;
  /** Colores del efecto de luz del bid actual (editable). Default: primary. */
  flashColors?: string[];
  /** Tipo de efecto de luz: "bulb" (bombilla) o "spin" (gira). Default "bulb". */
  flashMode?: "bulb" | "spin" | "explode" | "pulse" | "combo" | "shine";
}

export const SALA_WIDTH = 1023;
export const SALA_HEIGHT = 1042;

const SALA_IMAGES = ["/demo/bronco.jpg", "/demo/bronco.jpg", "/demo/bronco.jpg", "/demo/bronco.jpg"];

export default function Sala({ className = "", flashColors, flashMode = "bulb" }: SalaProps): JSX.Element {
  return (
    <div
      className={className}
      data-block="sala"
      style={{
        position: "relative",
        width: SALA_WIDTH,
        height: SALA_HEIGHT,
        background: "#2E0F70",
        overflow: "hidden",
      }}
    >
      {/* ConsoleHeader 991×64 · a 16px del top, centrado (16px a cada lado) */}
      <div style={{ position: "absolute", top: 16, left: 16 }}>
        <ConsoleHeader />
      </div>

      {/* Banner 204×930 · abajo-izquierda: 16px del left, 16px del bottom, 16px del header */}
      <div
        data-slot="left-banner"
        style={{
          position: "absolute",
          top: 96,
          left: 16,
          width: 204,
          height: 930,
          borderRadius: 8,
          background: "#E9EAEC",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          textAlign: "center",
          fontFamily: "monospace",
          fontSize: 12,
          letterSpacing: "0.08em",
          color: "#9AA1AC",
        }}
      >
        BANNER
        <br />
        204 × 930
      </div>

      {/* Columna derecha (443 ancho) · SalaStatus+visor (borde gradiente) ·
          filmstrip · y debajo la fila PRECIO BASE + pills */}
      <div
        style={{
          position: "absolute",
          top: 96,
          left: 236,
          width: 443,
          display: "flex",
          flexDirection: "column",
          gap: 16,
        }}
      >
        {/* El borde gradiente (slot header de CardViewer) envuelve SOLO
            SalaStatus + el visor; el filmstrip queda aparte, debajo. */}
        <CardViewer header={<SalaStatus />} images={SALA_IMAGES} />

        {/* Debajo del filmstrip · izquierda: PRECIO BASE (PriceIcon) ·
            derecha: 2 pills MIS BIDS / BIDS TOTALES (SendBidIcon) */}
        <div style={{ display: "flex", gap: 15, alignItems: "stretch" }}>
          <PriceBase />
          <div
            style={{
              flex: 1,
              display: "flex",
              flexDirection: "column",
              justifyContent: "space-between",
              gap: 12,
            }}
          >
            <StatPill variant="bids" label="MIS BIDS" value="18" />
            <StatPill variant="total" label="BIDS TOTALES" value="157" />
          </div>
        </div>

        {/* Banner inferior 443×237 · debajo de la fila PRECIO BASE + pills */}
        <div
          data-slot="bottom-banner"
          style={{
            width: 443,
            height: 237,
            borderRadius: 8,
            background: "#E9EAEC",
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            textAlign: "center",
            fontFamily: "monospace",
            fontSize: 12,
            letterSpacing: "0.08em",
            color: "#9AA1AC",
          }}
        >
          BANNER
          <br />
          443 × 237
        </div>
      </div>

      {/* Columna derecha (316) · BidChat y, debajo, BidPosition */}
      <div style={{ position: "absolute", top: 96, left: 691, display: "flex", flexDirection: "column", gap: 16 }}>
        <BidChat flashColors={flashColors} flashMode={flashMode} />
        <BidPosition />
      </div>
    </div>
  );
}

"use client";

/**
 * StatPill — Sección del bloque Sala (Voyager DS)
 * Fuente: Figma VOYAGER · "Background+Shadow (1)/(2)" (pill 156×47)
 *
 * Pill de estadística con SendBidIcon a la izquierda + label/valor a la derecha.
 * 3 variantes:
 *   · "bids"  → naranja (MIS BIDS) · SendBidIcon "white" (flecha naranja)
 *   · "total" → morado  (BIDS TOTALES) · SendBidIcon "vault" (flecha blanca)
 *   · "glass" → 50×22 glass real (interior translúcido + borde gradiente vía
 *               máscara ::before, sin bleed-through) · ícono custom
 * Reusa el componente SendBidIcon. Editable por props.
 */

import type { JSX, ReactNode } from "react";
import SendBidIcon from "../../components/SendBidIcon/SendBidIcon";

export type StatPillVariant = "bids" | "total" | "glass";

export interface StatPillProps {
  /** Variante de color (default "bids") */
  variant?: StatPillVariant;
  /** Etiqueta (default "MIS BIDS") */
  label?: string;
  /** Valor (default "18") */
  value?: string;
  /** Ícono custom (solo variante "glass"). Si se omite usa SendBidIcon. */
  icon?: ReactNode;
  className?: string;
}

